import { render, screen } from '@testing-library/react';
import { ThemeProvider } from './ThemeContext';
import UserProfile from './UserProfile';

const AllTheProviders = ({ children }) => {
  return (
    <ThemeProvider theme="dark">
      {children}
    </ThemeProvider>
  );
};

test('renders wrapped component without crashing', () => {
  render(<UserProfile />, { wrapper: AllTheProviders });
  expect(screen.getByText('Dark Mode User Profile')).toBeVisible();
});

import { setupServer } from 'msw/node';
import { http, HttpResponse } from 'msw';

// Define network stub
const server = setupServer(
  http.get('https://api.example.com/user', () => {
    return HttpResponse.json({ name: 'Jane Mocked' });
  })
);

// Standard test runner hooks
beforeAll(() => server.listen());
afterEach(() => server.resetHandlers());
afterAll(() => server.close());

test('displays user from mocked API', async () => {
  render(<UserDashboard />);

  // Use findBy to wait for async resolution
  const userName = await screen.findByText('Jane Mocked');
  expect(userName).toBeVisible();
});
